SELECT COUNT(*) AS usage_records_count
FROM usage_records
WHERE group_id = 1;

SELECT difference_percentage
FROM usage_differences
WHERE group_id = 1 AND technique_id = 2;

SELECT group_name
FROM groups
ORDER BY sample_size DESC;

SELECT AVG(usage_percentage) AS overall_average_usage_percentage
FROM usage_records
ORDER BY overall_average_usage_percentage DESC;

SELECT usage_count
FROM usage_records
WHERE usage_percentage > 50;

SELECT group_name, sample_size
FROM groups
ORDER BY sample_size DESC;

SELECT group_name
FROM groups
WHERE sample_size = (SELECT MAX(sample_size) FROM groups);
